import Header from "./../components/header/Header";

const Home = () => {
    return ( 
        <>
            <Header />

            <main className="section">
                <div className="container">

                    <ul className="content-list">
                        <li className="content-list__item">
                            <h2 className="title-2">Ваше здоровье в надёжных руках</h2>
                            <p>Профилактика, диагностика и лечение различных заболеваний: консультации специалистов, 
                                лабораторные исследования, терапия, хирургия и реабилитация. 
                                Индивидуальный план лечения, профессиональный уход и 
                                контрольное наблюдение после процедур.</p>
                        </li>
                    </ul>

                </div>
            </main>
        </>
    );
}
 
export default Home;
